import{_ as e,W as a,X as n,$ as s}from"./framework-586fce15.js";const i={},l=s(`<ul><li><a href="#1-environmental-varibles">1. environmental varibles</a><ul><li><a href="#11-view-variables">1.1. View variables</a><ul><li><a href="#111-view-default-environmental-variables">1.1.1. View default environmental variables</a></li><li><a href="#112-view-all-environmental-variables">1.1.2. View all environmental variables</a></li><li><a href="#113-view-by-echo">1.1.3. View by echo</a></li></ul></li><li><a href="#12-change-varibale">1.2. Change varibale</a><ul><li><a href="#121-delete-this-new-variable">1.2.1. delete this new variable</a></li><li><a href="#122-change-path">1.2.2. change PATH</a></li><li><a href="#123-temporary">1.2.3. temporary</a><ul><li><a href="#1231-%E7%94%A8%E6%88%B7%E8%BA%AB%E4%BB%BD%E7%99%BB%E9%99%86ubuntu%E6%9C%8D%E5%8A%A1%E5%99%A8%E7%94%A8%E6%88%B7%E7%9B%AE%E5%BD%95%E6%96%B0%E5%BB%BAbashrc%E6%96%87%E4%BB%B6%E5%B9%B6source%E4%B9%8B%E5%90%8E%E8%AE%BE%E7%BD%AE%E7%94%9F%E6%95%88%E4%BD%86%E6%98%AF%E4%BD%BF%E7%94%A8ssh%E9%87%8D%E7%99%BB%E4%B9%8B%E5%90%8E%E5%8F%91%E7%8E%B0%E4%B9%8B%E5%89%8D%E7%9A%84%E8%AE%BE%E7%BD%AE%E4%B8%8D%E5%86%8D%E7%94%9F%E6%95%88">1.2.3.1. 用户身份登陆ubuntu服务器，用户目录新建.bashrc文件并source之后设置生效，但是使用ssh重登之后发现之前的设置不再生效。</a></li></ul></li></ul></li></ul></li></ul><hr><h1 id="_1-environmental-varibles" tabindex="-1"><a class="header-anchor" href="#_1-environmental-varibles" aria-hidden="true">#</a> 1. environmental varibles</h1><h2 id="_1-1-view-variables" tabindex="-1"><a class="header-anchor" href="#_1-1-view-variables" aria-hidden="true">#</a> 1.1. View variables</h2><h3 id="_1-1-1-view-default-environmental-variables" tabindex="-1"><a class="header-anchor" href="#_1-1-1-view-default-environmental-variables" aria-hidden="true">#</a> 1.1.1. View default environmental variables</h3><p>Each user, including root, has a default set of environment variables that determine how the system looks, acts, and feels.</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code>$ <span class="token function">env</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>Variables are simply strings in key­value pairs. One value:<code>KEY=value</code>, multiple values:<code>KEY=value1:value2</code>.</p><p>Environment variables are always uppercase, as in <code>HOME</code>, <code>PATH</code>.</p><h3 id="_1-1-2-view-all-environmental-variables" tabindex="-1"><a class="header-anchor" href="#_1-1-2-view-all-environmental-variables" aria-hidden="true">#</a> 1.1.2. View all environmental variables</h3><p>This command will list all environment variables unique to your system.</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code>$ <span class="token builtin class-name">set</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code>$ <span class="token builtin class-name">set</span> <span class="token operator">|</span> <span class="token function">grep</span> <span class="token environment constant">HISTSIZE</span>
<span class="token assign-left variable"><span class="token environment constant">HISTSIZE</span></span><span class="token operator">=</span><span class="token number">1000</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="_1-1-3-view-by-echo" tabindex="-1"><a class="header-anchor" href="#_1-1-3-view-by-echo" aria-hidden="true">#</a> 1.1.3. View by echo</h3><p>Only <code>echo $VARIABLE</code> has <code>$</code>.</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code>$ <span class="token builtin class-name">echo</span> <span class="token environment constant">$HISTSIZE</span>
<span class="token number">1000</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="_1-2-change-varibale" tabindex="-1"><a class="header-anchor" href="#_1-2-change-varibale" aria-hidden="true">#</a> 1.2. Change varibale</h2><h3 id="_1-2-1-delete-this-new-variable" tabindex="-1"><a class="header-anchor" href="#_1-2-1-delete-this-new-variable" aria-hidden="true">#</a> 1.2.1. delete this new variable</h3><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code>$ <span class="token builtin class-name">unset</span> VARIABLE
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><blockquote><p>Question: Is it different between <code>unset VARIABLE</code> and <code>VARIABLE=&#39;&#39;</code>?</p></blockquote><h3 id="_1-2-2-change-path" tabindex="-1"><a class="header-anchor" href="#_1-2-2-change-path" aria-hidden="true">#</a> 1.2.2. change PATH</h3><p>To add <code>newhackingtool</code> to your <code>PATH</code> variable, this directory should be appended to the end of <code>PATH</code>, not be replaced.</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code>$ <span class="token assign-left variable"><span class="token environment constant">PATH</span></span><span class="token operator">=</span>/root/newhackingtool:<span class="token environment constant">$PATH</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>PS: <code>/root/newhackingtool</code> is in front of <code>$PATH</code>, then <code>/root/newhackingtool</code> is firstly searched.</p><h3 id="_1-2-3-temporary" tabindex="-1"><a class="header-anchor" href="#_1-2-3-temporary" aria-hidden="true">#</a> 1.2.3. temporary</h3><blockquote><p>这有什么用？</p></blockquote><p>When you change an environment variable, that change only occurs in that bash shell session. This means that when you close the terminal, any changes you made are lost, with values set back to their defaults.</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code>$ <span class="token assign-left variable"><span class="token environment constant">HISTSIZE</span></span><span class="token operator">=</span><span class="token number">0</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><blockquote><p>Question: permanent? This doesn&#39;t work. So what is the effect of export?</p></blockquote><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code>$ <span class="token assign-left variable"><span class="token environment constant">HISTSIZE</span></span><span class="token operator">=</span><span class="token number">0</span>
$ <span class="token builtin class-name">export</span> <span class="token environment constant">HISTSIZE</span>

<span class="token comment"># or</span>
$ <span class="token builtin class-name">export</span> <span class="token assign-left variable"><span class="token environment constant">HISTSIZE</span></span><span class="token operator">=</span><span class="token number">0</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><blockquote><p>修改<code>~/.bashrc</code>或<code>/etc/profile</code>。</p></blockquote><ul><li><code>~/.bashrc</code>: 该文件包含专用于<strong>某个用户</strong><code>~</code>的bash shell信息，当该用户登录时以及每次打开新的shell时,该文件被读取。</li><li><code>/etc/profile</code>: 设定的变量可以作用于<strong>任何用户</strong>，而<code>~/.bashrc</code>等中设定的变量继承<code>/etc/profile</code>中的变量。</li></ul><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token builtin class-name">echo</span> <span class="token string">&quot;export PATH=<span class="token environment constant">$PATH</span>:/usr/local/cuda-11.0/bin&quot;</span> <span class="token operator">&gt;&gt;</span> ~/.bashrc
<span class="token builtin class-name">echo</span> <span class="token string">&quot;export LD_LIBRARY_PATH=<span class="token variable">$LD_LIBRARY_PATH</span>:/usr/local/cuda-11.0/lib64&quot;</span> <span class="token operator">&gt;&gt;</span> ~/.bashrc
<span class="token builtin class-name">source</span> ~/.bashrc
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><blockquote><p>保存之后，两种生效方式：</p></blockquote><ol><li>如果不执行 source 命令，则需重启系统才能生效。</li><li>source 命令使这个修改立即生效。</li></ol><p>PS: source的生效只是临时在当前终端生效。即重新开启一个终端后，该环境变量失效，新的终端还得再使用source命令。而重启后的生效是都生效。</p><h4 id="_1-2-3-1-用户身份登陆ubuntu服务器-用户目录新建-bashrc文件并source之后设置生效-但是使用ssh重登之后发现之前的设置不再生效。" tabindex="-1"><a class="header-anchor" href="#_1-2-3-1-用户身份登陆ubuntu服务器-用户目录新建-bashrc文件并source之后设置生效-但是使用ssh重登之后发现之前的设置不再生效。" aria-hidden="true">#</a> 1.2.3.1. 用户身份登陆ubuntu服务器，用户目录新建.bashrc文件并source之后设置生效，但是使用ssh重登之后发现之前的设置不再生效。</h4><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token comment"># 环境变量，必须等每次source才能加载</span>
~$ <span class="token builtin class-name">echo</span> <span class="token environment constant">$PATH</span>
/usr/local/sbin:/usr/local/bin:/usr/sbin:/usr/bin:/sbin:/bin:/usr/games:/usr/local/games:/snap/bin
~$ <span class="token builtin class-name">source</span> ~/.bashrc
~$ <span class="token builtin class-name">echo</span> <span class="token environment constant">$PATH</span>
/usr/local/cuda-11.7/bin:/home/lenovo/miniconda3/condabin:/home/lenovo/miniconda3/bin:/usr/local/sbin:/usr/local/bin:/usr/sbin:/usr/bin:/sbin:/bin:/usr/games:/usr/local/games:/snap/bin
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>新建一个<code>.profile</code>文件，添加自动运行<code>.bashrc</code>的配置信息</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token comment"># if running bash</span>
<span class="token keyword">if</span> <span class="token punctuation">[</span> <span class="token parameter variable">-n</span> <span class="token string">&quot;<span class="token environment constant">$BASH_VERSION</span>&quot;</span> <span class="token punctuation">]</span><span class="token punctuation">;</span> <span class="token keyword">then</span>
    <span class="token comment"># include .bashrc if it exists</span>
    <span class="token keyword">if</span> <span class="token punctuation">[</span> <span class="token parameter variable">-f</span> <span class="token string">&quot;<span class="token environment constant">$HOME</span>/.bashrc&quot;</span> <span class="token punctuation">]</span><span class="token punctuation">;</span> <span class="token keyword">then</span>
        <span class="token builtin class-name">.</span> <span class="token string">&quot;<span class="token environment constant">$HOME</span>/.bashrc&quot;</span>
    <span class="token keyword">fi</span>
<span class="token keyword">fi</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><code>~/.profile</code>: executed by the command interpreter for login shells. This file is not read by bash(1), if <code>~/.bash_profile</code> or <code>~/.bash_login</code> exists.</p>`,41),o=[l];function t(r,c){return a(),n("div",null,o)}const p=e(i,[["render",t],["__file","environmental variables.html.vue"]]);export{p as default};
